import hashlib
import time

class Block:
 def __init__(self, index, previous_hash, timestamp, data):
 self.index = index
 self.previous_hash = previous_hash
 self.timestamp = timestamp
 self.data = data
 self.hash = self.calculate_hash()

 def calculate_hash(self):
 data_string = str(self.index) + self.previous_hash + str(self.timestamp) + str(self.data)
 return hashlib.sha256(data_string.encode()).hexdigest()

class Blockchain:
 def __init__(self):
 self.chain = [self.create_genesis_block()]

 def create_genesis_block(self):
 return Block(0, '0', int(time.time()), 'Genesis Block')

 def get_latest_block(self):
 return self.chain[-1]

 def add_block(self, new_block):
 new_block.previous_hash = self.get_latest_block().hash
 new_block.hash = new_block.calculate_hash()
 self.chain.append(new_block)

# Create a blockchain and add some blocks
blockchain = Blockchain()
blockchain.add_block(Block(1, blockchain.get_latest_block().hash, int(time.time()), 'Transaction 1'))
blockchain.add_block(Block(2, blockchain.get_latest_block().hash, int(time.time()), 'Transaction 2'))

import java.util.ArrayList;
import java.util.List;

public class DistributedSystem {
 private List<Node> nodes;

 public DistributedSystem() {
 this.nodes = new ArrayList<>();
 }

 public void addNode(Node node) {
 nodes.add(node);
 }

 public void broadcastTransaction(Transaction transaction) {
 for (Node node : nodes) {
 node.receiveTransaction(transaction);
 }
 }

 public static class Node {
 private String id;

 public Node(String id) {
 this.id = id;
 }

 public void receiveTransaction(Transaction transaction) {
 System.out.println(id + " received transaction: " + transaction);
 }
 }

 public static class Transaction {
 private String data;

 public Transaction(String data) {
 this.data = data;
 }

 @Override
 public String toString() {
 return data;
 }
 }

 public static void main(String[] args) {
 DistributedSystem distributedSystem = new DistributedSystem();
 distributedSystem.addNode(new Node("Node 1"));
 distributedSystem.addNode(new Node("Node 2"));
 distributedSystem.broadcastTransaction(new Transaction("Transaction 1"));
 }
}
